import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"魔导控制台","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/8.物品改造/魔导控制台.md","filePath":"4.资源分区/7.物品与装备/8.物品改造/魔导控制台.md"}'),d={name:"4.资源分区/7.物品与装备/8.物品改造/魔导控制台.md"};function _(l,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"魔导控制台",tabindex:"-1"},[s("魔导控制台 "),e("a",{class:"header-anchor",href:"#魔导控制台","aria-label":'Permalink to "魔导控制台"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘002")])])],-1),o('<h1 id="魔导控制台-1" tabindex="-1">魔导控制台 <a class="header-anchor" href="#魔导控制台-1" aria-label="Permalink to &quot;魔导控制台&quot;">​</a></h1><p>魔导控制台<br> D+500<br> 只能在驾驶载具时使用，外形为一个圆形魔法阵，当使用者站立其上时会面前会出现两个较大的光球让使用者抓住作为主操纵杆，一些小型法阵悬浮于附近作为按键。<br> 驱动阵式：魔导控制台本身视为一个必须要双手才能操纵的法杖。提供3点法强。<br> 控制连接：该法阵将作为一种操作方式替代原本的操作系统进行操纵，使用者使用法术时可以选择向控制台发送能量，能量将被控制台传送至载具表面（可以自行决定位置）再形成法术，这是一个D级传送效果。举例来说，一名驾驶坦克的魔法师可以释放火球术令其从炮筒形成，从而产生让坦克发射火球的画风表现，一名驾驶机器人的魔法师释放落雷术，可以表现为战斗机器人指向天空发射雷电，随后降下落雷攻击敌人。这个效果只是让法术能在载具中使用，检定方式与射程等不受影响。<br> 法器插槽：特殊的，你可以将一柄法器（法杖，魔导书等）放置于法阵，将二者结合使用，在施法时提供的法强为二者之间的较高者，两者除法强外的效果正常生效。需要注意的是，魔导控制台必须双手才能操纵，所以除了魔导控制台与插入的法器，你无法再装备其他法器。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
